package main

import "fmt"

func reverseKGroup(nums []int, k int) []int {

	n := len(nums)

	for i := 0; i < n; i += k {

		left := i
		right := min(i+k-1, n-1)

		// 反转当前组
		for left < right {
			nums[left], nums[right] = nums[right], nums[left]
			left++
			right--
		}
	}

	return nums
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}

func main() {

	nums := []int{1, 2, 3, 4, 5, 6, 7, 8}
	k := 3

	result := reverseKGroup(nums, k)

	fmt.Println(result)
}
